sql:
SELECT applicant_name 
FROM applicants 
ORDER BY date_of_birth ASC;

SELECT COUNT(*) 
FROM job_postings
WHERE pay_scale_id < (SELECT AVG(pay_scale_id) FROM pay_scales);

SELECT offer_id
FROM job_offers
WHERE offer_status = 'rejected';

SELECT COUNT(*) 
FROM job_categories 
WHERE category_id NOT IN (SELECT category_id FROM job_postings);

external_knowledge:
- 'young engineers' refers to applicants in the 'Engineering' category;
- 'Grade A salary' refers to applicants applying for positions with a 'Grade A' pay scale;
- The average age is calculated from the date of birth column;
- The metaphorical sea of job opportunities is used to represent the extensive range of job postings available.

sql:
SELECT posting_name, vacancies
FROM job_postings
ORDER BY vacancies DESC;

external_knowledge:
- 'gigs' refers to job postings;
- 'avenues' refers to the job categories;
- 'geographical territories' refers to the locations where the jobs are based;
- 'sowers of seeds who have sown their 30 years of wisdom' refers to individuals aged 30 years;
- 'golden offers' refers to accepted job offers.
